# Explorer notes for S43-T1-A-E2: follow packet fixture + instruction contract
def assess(record: dict) -> str:
    required = {'dependency_layer_reused', 'lock_copied_before_source', 'source_change_rebuilds', 'digest_stable', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not (not record["dependency_layer_reused"] and record["source_change_rebuilds"] > 3) else "REORDER_DOCKERFILE"

valid = {'case_id': 'CASO-TRU-043-1A', 'lock_copied_before_source': True, 'dependency_layer_reused': True, 'source_change_rebuilds': 1, 'digest_stable': True}
invalid = {'case_id': 'CASO-TRU-043-1A', 'lock_copied_before_source': True, 'dependency_layer_reused': True, 'source_change_rebuilds': 1, 'digest_stable': True, '_adversarial': True}
incomplete = {**valid}
incomplete.pop('digest_stable', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

